#!/usr/bin/env python3
"""Generate Grafana error pages to reach 100+ total."""
import os

BASE = '/home/admin1/projects/ErrorCode.excellentwiki.com/content/tools/grafana'
EXISTING = {f.replace('.md', '') for f in os.listdir(BASE) if f.endswith('.md')}

def make_page(slug, title, desc, body):
    return f'''---
title: "[Solution] {title}"
description: "{desc}"
tools: ["grafana"]
error-types: ["tool-error"]
severities: ["error"]
---

{body}
'''

PAGES = [
    ("grafana-dashboard-not-found", "Grafana Dashboard Not Found", "How to fix Grafana dashboard not found errors", "## Common Causes\n\n- Dashboard deleted or moved\n- Wrong dashboard UID in URL\n- Dashboard provisioned under different org\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/search?query=my-dashboard | jq '.[].uid'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/search | jq '.[].title'\n```"),
    ("grafana-dashboard-version-conflict", "Grafana Dashboard Version Conflict", "How to fix Grafana dashboard save conflict", "## Common Causes\n\n- Two users editing simultaneously\n- Provisioning overwriting manual edits\n- API call with stale version\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.version'\n```\n\n## Examples\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"dashboard\":{\"uid\":\"UID\",\"version\":5},\"overwrite\":true}' http://localhost:3000/api/dashboards/db\n```"),
    ("grafana-panel-not-found", "Grafana Panel Not Found", "How to fix Grafana panel not found errors", "## Common Causes\n\n- Panel deleted from dashboard\n- Panel ID changed after reimport\n- JSON model corrupted\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | {id: .id, title: .title}'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | \"\\\\(.id): \\\\(.title)\"'\n```"),
    ("grafana-datasource-not-found", "Grafana Datasource Not Found", "How to fix Grafana datasource not found errors", "## Common Causes\n\n- Datasource deleted from Grafana\n- Wrong datasource UID in panel\n- Datasource provisioned under different org\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/datasources | jq '.[].name'\n```\n\n## Examples\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"name\":\"Prometheus\",\"type\":\"prometheus\",\"url\":\"http://prometheus:9090\",\"access\":\"proxy\"}' http://localhost:3000/api/datasources\n```"),
    ("grafana-datasource-not-working", "Grafana Datasource Not Working", "How to fix Grafana datasource connection failures", "## Common Causes\n\n- Datasource URL unreachable\n- Authentication credentials expired\n- TLS certificate verification failure\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/datasources/uid/ABC123/health | jq '.status'\n```\n\n## Examples\n\n```bash\ncurl -H \"Authorization: Bearer API_KEY\" \"http://localhost:3000/api/datasources/proxy/ABC123/api/v1/query?query=up\"\n```"),
    ("grafana-plugin-signature-invalid", "Grafana Plugin Signature Invalid", "How to fix Grafana plugin signature errors", "## Common Causes\n\n- Plugin not signed by Grafana\n- Modified plugin files\n- Plugin from unofficial repository\n\n## How to Fix\n\n```ini\n[plugins]\nallow_loading_unsigned_plugins = my-custom-plugin\n```\n\n## Examples\n\n```bash\ngrafana-cli plugins install grafana-clock-panel --force\n```"),
    ("grafana-plugin-unsigned", "Grafana Plugin Unsigned Error", "How to fix Grafana unsigned plugin errors", "## Common Causes\n\n- Custom plugin not signed\n- Plugin from third-party source\n- Enterprise plugin without license\n\n## How to Fix\n\n```ini\n[plugins]\nallow_loading_unsigned_plugins = custom-plugin-1\ndisable_signature_validation = true\n```\n\n## Examples\n\n```bash\nls -la /var/lib/grafana/plugins/my-plugin/\n```"),
    ("grafana-plugin-dependency-error", "Grafana Plugin Dependency Error", "How to fix Grafana plugin dependency errors", "## Common Causes\n\n- Required Grafana version mismatch\n- Missing companion plugin\n- Node.js version mismatch\n\n## How to Fix\n\n```bash\ngrafana-cli --version\nsudo apt-get install grafana\nsudo systemctl restart grafana-server\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/plugins | jq '.[] | {id: .id, version: .info.version}'\n```"),
    ("grafana-dashboard-provisioning-error", "Grafana Dashboard Provisioning Error", "How to fix Grafana dashboard provisioning failures", "## Common Causes\n\n- Dashboard JSON syntax error\n- Missing required fields\n- Datasource references not matching\n\n## How to Fix\n\n```yaml\napiVersion: 1\nproviders:\n  - name: 'default'\n    orgId: 1\n    folder: 'Monitoring'\n    type: file\n    options:\n      path: /var/lib/grafana/dashboards\n```\n\n## Examples\n\n```bash\npython3 -m json.tool /var/lib/grafana/dashboards/my-dashboard.json\n```"),
    ("grafana-datasource-provisioning-error", "Grafana Datasource Provisioning Error", "How to fix Grafana datasource provisioning errors", "## Common Causes\n\n- Datasource URL unreachable during provisioning\n- Authentication credentials wrong\n- Duplicate datasource names\n\n## How to Fix\n\n```yaml\napiVersion: 1\ndatasources:\n  - name: Prometheus\n    type: prometheus\n    access: proxy\n    url: http://prometheus:9090\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/datasources | jq '.[].name'\n```"),
    ("grafana-alert-provisioning-error", "Grafana Alert Provisioning Error", "How to fix Grafana alert provisioning errors", "## Common Causes\n\n- Alert rule references non-existent datasource\n- Invalid query in alert rule\n- Notification channel not provisioned\n\n## How to Fix\n\n```yaml\napiVersion: 1\ngroups:\n  - orgId: 1\n    name: Example\n    folder: Alerting\n    interval: 1m\n    rules:\n      - uid: alert-1\n        title: High Error Rate\n        condition: C\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/v1/provisioning/alert-rules | jq '.[].title'\n```"),
    ("grafana-notifier-provisioning-error", "Grafana Notifier Provisioning Error", "How to fix Grafana notification provisioning errors", "## Common Causes\n\n- Invalid webhook URL\n- Missing required fields\n- Duplicate contact point names\n\n## How to Fix\n\n```yaml\napiVersion: 1\ncontactPoints:\n  - orgId: 1\n    name: slack-alerts\n    receivers:\n      - uid: slack-channel\n        type: slack\n        settings:\n          url: https://hooks.slack.com/services/T00/B00/xxx\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/v1/provisioning/contact-points | jq '.[].name'\n```"),
    ("grafana-api-key-invalid", "Grafana API Key Invalid", "How to fix Grafana API key authentication errors", "## Common Causes\n\n- API key deleted or revoked\n- API key expired\n- Wrong API key format\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer ADMIN_KEY\" -d '{\"name\":\"my-key\",\"role\":\"Viewer\"}' http://localhost:3000/api/auth/keys\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer ADMIN_KEY\" http://localhost:3000/api/auth/keys | jq '.[].name'\n```"),
    ("grafana-api-key-expired", "Grafana API Key Expired", "How to fix Grafana API key expiration errors", "## Common Causes\n\n- API key reached max lifetime\n- Default expiration policy\n- Organization policy enforcing rotation\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer ADMIN_KEY\" http://localhost:3000/api/auth/keys | jq '.[] | {name: .name, expires: .expiration}'\n```\n\n## Examples\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer ADMIN_KEY\" -d '{\"name\":\"long-lived\",\"role\":\"Viewer\",\"secondsToLive\":31536000}' http://localhost:3000/api/auth/keys\n```"),
    ("grafana-org-not-found", "Grafana Organization Not Found", "How to fix Grafana organization not found errors", "## Common Causes\n\n- Organization deleted\n- Wrong org ID in API request\n- User not member of requested org\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer ADMIN_KEY\" http://localhost:3000/api/orgs | jq '.[].name'\n```\n\n## Examples\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer ADMIN_KEY\" -d '{\"name\":\"NewOrg\"}' http://localhost:3000/api/orgs\n```"),
    ("grafana-org-role-error", "Grafana Organization Role Error", "How to fix Grafana org role assignment errors", "## Common Causes\n\n- Role level too low\n- Default role assignment incorrect\n- Missing Admin role\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer ADMIN_KEY\" http://localhost:3000/api/org/users | jq '.[] | {login: .login, role: .role}'\n```\n\n## Examples\n\n```bash\ncurl -X PATCH -H \"Content-Type: application/json\" -H \"Authorization: Bearer ADMIN_KEY\" -d '{\"role\":\"Admin\"}' http://localhost:3000/api/org/users/2\n```"),
    ("grafana-user-not-found", "Grafana User Not Found", "How to fix Grafana user not found errors", "## Common Causes\n\n- Username or email does not exist\n- User was deleted\n- Searching in wrong organization\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer ADMIN_KEY\" \"http://localhost:3000/api/users?query=admin\" | jq '.[].login'\n```\n\n## Examples\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer ADMIN_KEY\" -d '{\"name\":\"John\",\"email\":\"john@example.com\",\"login\":\"john\",\"password\":\"secret\"}' http://localhost:3000/api/admin/users\n```"),
    ("grafana-user-permission-error", "Grafana User Permission Error", "How to fix Grafana user permission denied errors", "## Common Causes\n\n- User role insufficient\n- Datasource permission restrictions\n- Folder permissions blocking access\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer ADMIN_KEY\" -d '{\"userId\":2,\"role\":\"Editor\"}' http://localhost:3000/api/org/users\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer ADMIN_KEY\" http://localhost:3000/api/folders/1/permissions | jq '.'\n```"),
    ("grafana-team-not-found", "Grafana Team Not Found", "How to fix Grafana team not found errors", "## Common Causes\n\n- Team deleted or not created\n- Wrong team ID or name\n- Team in different organization\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer ADMIN_KEY\" http://localhost:3000/api/teams/search | jq '.teams[].name'\n```\n\n## Examples\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer ADMIN_KEY\" -d '{\"name\":\"DevOps\",\"email\":\"devops@example.com\"}' http://localhost:3000/api/teams\n```"),
    ("grafana-team-permission-error", "Grafana Team Permission Error", "How to fix Grafana team permission errors", "## Common Causes\n\n- Team does not have access to folder\n- Team role insufficient\n- External group sync not working\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer ADMIN_KEY\" -d '{\"items\":[{\"teamId\":1,\"permission\":2}]}' http://localhost:3000/api/folders/1/permissions\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer ADMIN_KEY\" http://localhost:3000/api/teams/1/members | jq '.[].login'\n```"),
    ("grafana-folder-not-found", "Grafana Folder Not Found", "How to fix Grafana folder not found errors", "## Common Causes\n\n- Folder deleted\n- Wrong folder UID\n- Provisioned folder in different org\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer ADMIN_KEY\" http://localhost:3000/api/folders | jq '.[].title'\n```\n\n## Examples\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer ADMIN_KEY\" -d '{\"title\":\"Monitoring\"}' http://localhost:3000/api/folders\n```"),
    ("grafana-folder-permission-error", "Grafana Folder Permission Error", "How to fix Grafana folder permission denied errors", "## Common Causes\n\n- User not granted access to folder\n- Team permissions not configured\n- Default folder permissions too restrictive\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer ADMIN_KEY\" -d '{\"items\":[{\"userId\":2,\"permission\":2}]}' http://localhost:3000/api/folders/FOLDER_UID/permissions\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer ADMIN_KEY\" http://localhost:3000/api/folders/FOLDER_UID/permissions | jq '.items[]'\n```"),
    ("grafana-annotation-tag-error", "Grafana Annotation Tag Filter Error", "How to fix Grafana annotation tag filtering errors", "## Common Causes\n\n- Tag name case sensitivity\n- Too many tags causing timeout\n- Tag filter syntax incorrect\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" \"http://localhost:3000/api/annotations?tags=deployment&tags=production\"\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" \"http://localhost:3000/api/annotations?tags=deploy\"\n```"),
    ("grafana-alert-rule-evaluation-error", "Grafana Alert Rule Evaluation Error", "How to fix Grafana alert rule evaluation failures", "## Common Causes\n\n- Datasource query timing out\n- Insufficient data for evaluation\n- Expression returning no data\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/v1/rules | jq '.data.groups[].rules[] | select(.health == \"error\")'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/v1/rules | jq '.data.groups[].rules[] | {name: .name, health: .health, state: .state}'\n```"),
    ("grafana-alert-state-error", "Grafana Alert State Error", "How to fix Grafana alert state management issues", "## Common Causes\n\n- Alert stuck in Pending state\n- Alert transitioning to Error state\n- Alert not resolving when condition clears\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/alertmanager/grafana/api/v2/alerts | jq '.[] | {labels: .labels, status: .status.state}'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/alertmanager/grafana/api/v2/alerts | jq '.[] | select(.status.state == \"active\") | .labels.alertname'\n```"),
    ("grafana-alert-notification-error", "Grafana Alert Notification Error", "How to fix Grafana alert notification delivery errors", "## Common Causes\n\n- Notification channel unreachable\n- Webhook URL incorrect\n- Email server not configured\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/alert-notifications | jq '.[].name'\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"id\":1}' http://localhost:3000/api/alert-notifications/test\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/alert-notifications | jq '.[].name'\n```"),
    ("grafana-alert-channel-error", "Grafana Alert Channel Error", "How to fix Grafana alert channel configuration errors", "## Common Causes\n\n- Channel type not supported\n- Missing required settings\n- Channel disabled or deleted\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"name\":\"slack\",\"type\":\"slack\",\"settings\":{\"url\":\"https://hooks.slack.com/services/T00/B00/xxx\",\"recipient\":\"#alerts\"}}' http://localhost:3000/api/alert-notifications\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/alert-notifications | jq '.[] | {id: .id, name: .name, type: .type}'\n```"),
    ("grafana-email-notifier-error", "Grafana Email Notifier Error", "How to fix Grafana email notification errors", "## Common Causes\n\n- SMTP server not configured\n- SMTP authentication failure\n- SMTP TLS/STARTTLS error\n\n## How to Fix\n\n```ini\n[smtp]\nenabled = true\nhost = smtp.gmail.com:587\nuser = alerts@example.com\npassword = your-password\nfrom_address = grafana@example.com\n```\n\n## Examples\n\n```bash\njournalctl -u grafana-server | grep -i smtp\n```"),
    ("grafana-slack-notifier-error", "Grafana Slack Notifier Error", "How to fix Grafana Slack notification errors", "## Common Causes\n\n- Slack webhook URL revoked\n- Channel name incorrect\n- Message format exceeding limits\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"name\":\"slack\",\"type\":\"slack\",\"settings\":{\"url\":\"https://hooks.slack.com/services/T00/B00/xxx\",\"recipient\":\"#alerts\"}}' http://localhost:3000/api/alert-notifications\n```\n\n## Examples\n\n```bash\ncurl -X POST https://hooks.slack.com/services/T00/B00/xxx -H 'Content-Type: application/json' -d '{\"text\":\"Test from Grafana\"}'\n```"),
    ("grafana-pagerduty-notifier-error", "Grafana PagerDuty Notifier Error", "How to fix Grafana PagerDuty notification errors", "## Common Causes\n\n- Integration key invalid\n- Severity level not set\n- API endpoint unreachable\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"name\":\"pd\",\"type\":\"pagerduty\",\"settings\":{\"integrationKey\":\"key\",\"severity\":\"critical\"}}' http://localhost:3000/api/alert-notifications\n```\n\n## Examples\n\n```bash\njournalctl -u grafana-server | grep -i pagerduty\n```"),
    ("grafana-webhook-notifier-error", "Grafana Webhook Notifier Error", "How to fix Grafana webhook notification errors", "## Common Causes\n\n- Webhook URL unreachable\n- HTTP timeout during notification\n- Invalid JSON payload\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"name\":\"webhook\",\"type\":\"webhook\",\"settings\":{\"url\":\"http://handler:5001/alerts\",\"httpMethod\":\"POST\"}}' http://localhost:3000/api/alert-notifications\n```\n\n## Examples\n\n```bash\ncurl -X POST http://handler:5001/alerts -H 'Content-Type: application/json' -d '{\"title\":\"Test\",\"state\":\"alerting\",\"message\":\"Test\"}'\n```"),
    ("grafana-opsgenie-notifier-error", "Grafana OpsGenie Notifier Error", "How to fix Grafana OpsGenie notification errors", "## Common Causes\n\n- Invalid API key\n- Wrong API URL (EU vs US)\n- Missing message field\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"name\":\"opsgenie\",\"type\":\"opsgenie\",\"settings\":{\"apiKey\":\"key\",\"apiUrl\":\"https://api.opsgenie.com\"}}' http://localhost:3000/api/alert-notifications\n```\n\n## Examples\n\n```bash\njournalctl -u grafana-server | grep -i opsgenie\n```"),
    ("grafana-victorops-notifier-error", "Grafana VictorOps Notifier Error", "How to fix Grafana VictorOps notification errors", "## Common Causes\n\n- Invalid routing key\n- VictorOps API URL wrong\n- Webhook URL malformed\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"name\":\"victorops\",\"type\":\"victorops\",\"settings\":{\"url\":\"https://alert.victorops.com/integrations/generic/20131114/alert/ROUTING_KEY\"}}' http://localhost:3000/api/alert-notifications\n```\n\n## Examples\n\n```bash\njournalctl -u grafana-server | grep -i victorops\n```"),
    ("grafana-discord-notifier-error", "Grafana Discord Notifier Error", "How to fix Grafana Discord notification errors", "## Common Causes\n\n- Invalid Discord webhook URL\n- Webhook URL expired\n- Bot not present in channel\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"name\":\"discord\",\"type\":\"discord\",\"settings\":{\"url\":\"https://discord.com/api/webhooks/YOUR_WEBHOOK\"}}' http://localhost:3000/api/alert-notifications\n```\n\n## Examples\n\n```bash\ncurl -X POST https://discord.com/api/webhooks/YOUR_WEBHOOK -H \"Content-Type: application/json\" -d '{\"content\":\"Test alert\"}'\n```"),
    ("grafana-telegram-notifier-error", "Grafana Telegram Notifier Error", "How to fix Grafana Telegram notification errors", "## Common Causes\n\n- Invalid bot token\n- Chat ID not found\n- Bot not added to group\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"name\":\"telegram\",\"type\":\"telegram\",\"settings\":{\"bottoken\":\"TOKEN\",\"chatid\":\"-1001234567890\"}}' http://localhost:3000/api/alert-notifications\n```\n\n## Examples\n\n```bash\ncurl -X POST \"https://api.telegram.org/botYOUR_TOKEN/sendMessage\" -d \"chat_id=-1001234567890&text=Test alert\"\n```"),
    ("grafana-pushover-notifier-error", "Grafana Pushover Notifier Error", "How to fix Grafana Pushover notification errors", "## Common Causes\n\n- Invalid user key or API token\n- Message priority too high\n- Device name not specified\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"name\":\"pushover\",\"type\":\"pushover\",\"settings\":{\"userKey\":\"KEY\",\"apiToken\":\"TOKEN\",\"priority\":\"0\"}}' http://localhost:3000/api/alert-notifications\n```\n\n## Examples\n\n```bash\njournalctl -u grafana-server | grep -i pushover\n```"),
    ("grafana-line-notifier-error", "Grafana LINE Notifier Error", "How to fix Grafana LINE notification errors", "## Common Causes\n\n- Invalid channel access token\n- Channel ID incorrect\n- LINE Notify API unreachable\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"name\":\"line\",\"type\":\"line\",\"settings\":{\"token\":\"TOKEN\"}}' http://localhost:3000/api/alert-notifications\n```\n\n## Examples\n\n```bash\ncurl -X POST https://notify-api.line.me/api/notify -H \"Authorization: Bearer TOKEN\" -d \"message=Test from Grafana\"\n```"),
    ("grafana-threema-notifier-error", "Grafana Threema Notifier Error", "How to fix Grafana Threema notification errors", "## Common Causes\n\n- Invalid gateway ID or secret\n- Recipient Threema ID wrong\n- Message format error\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"name\":\"threema\",\"type\":\"threema\",\"settings\":{\"gateway_id\":\"*GATEWAY\",\"recipient_id\":\"RECIPIENT\",\"secret\":\"SECRET\"}}' http://localhost:3000/api/alert-notifications\n```\n\n## Examples\n\n```bash\njournalctl -u grafana-server | grep -i threema\n```"),
    ("grafana-teamsync-error", "Grafana Team Sync Error", "How to fix Grafana team synchronization errors", "## Common Causes\n\n- LDAP group mapping incorrect\n- OAuth claim not matching team\n- External group not configured\n\n## How to Fix\n\n```ini\n[auth.ldap]\nenabled = true\nconfig_file = /etc/grafana/ldap.toml\n```\n\n## Examples\n\n```bash\nldapsearch -x -H ldap://ldap-server -b \"ou=users,dc=example,dc=com\" \"(cn=admin)\"\n```"),
    ("grafana-image-renderer-error", "Grafana Image Renderer Error", "How to fix Grafana image rendering failures", "## Common Causes\n\n- Image renderer plugin not installed\n- Chrome/Chromium not available\n- Out of memory during rendering\n\n## How to Fix\n\n```bash\ngrafana-cli plugins install grafana-image-renderer\nsudo systemctl restart grafana-server\n```\n\n## Examples\n\n```bash\ncurl -H \"Authorization: Bearer API_KEY\" \"http://localhost:3000/render/d/UID?orgId=1&width=1000&height=500\" -o dashboard.png\n```"),
    ("grafana-live-error", "Grafana Live Error", "How to fix Grafana Live WebSocket errors", "## Common Causes\n\n- WebSocket connection blocked by proxy\n- Channel limit exceeded\n- Live service not enabled\n\n## How to Fix\n\n```ini\n[live]\nenabled = true\nmax_connections = 100\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/live/status | jq '.enabled'\n```"),
    ("grafana-snapshot-error", "Grafana Snapshot Error", "How to fix Grafana dashboard snapshot errors", "## Common Causes\n\n- Snapshot storage not configured\n- Snapshot too large\n- External snapshot server unreachable\n\n## How to Fix\n\n```ini\n[snapshots]\nexternal_enabled = true\n```\n\n## Examples\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"dashboard\":{},\"expires\":86400}' http://localhost:3000/api/snapshots\n```"),
    ("grafana-explore-error", "Grafana Explore Error", "How to fix Grafana Explore query errors", "## Common Causes\n\n- Datasource not configured for Explore\n- Query syntax error\n- Query timeout exceeded\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/datasources | jq '.[] | select(.type == \"prometheus\")'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/datasources | jq '.[].name'\n```"),
    ("grafana-cortex-error", "Grafana Cortex Error", "How to fix Grafana Cortex backend errors", "## Common Causes\n\n- Cortex endpoint unreachable\n- Authentication misconfigured\n- API version mismatch\n\n## How to Fix\n\n```yaml\ntype: prometheus\nurl: http://cortex:9009\njsonData:\n  httpMethod: POST\n```\n\n## Examples\n\n```bash\ncurl http://cortex:9009/api/v1/status/config\n```"),
    ("grafana-data-transform-error", "Grafana Data Transform Error", "How to fix Grafana data transformation errors", "## Common Causes\n\n- Transform type not recognized\n- Input field name mismatch\n- Reduce operation on empty data\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[].transformations[]'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard' > dashboard.json\n```"),
    ("grafana-bar-gauge-error", "Grafana Bar Gauge Error", "How to fix Grafana bar gauge panel errors", "## Common Causes\n\n- Threshold values incorrectly ordered\n- Data returned as string\n- Bar gauge height too small\n\n## How to Fix\n\n```json\n{\n  \"fieldConfig\": {\n    \"defaults\": {\n      \"thresholds\": {\n        \"mode\": \"absolute\",\n        \"steps\": [\n          {\"color\": \"green\", \"value\": null},\n          {\"color\": \"yellow\", \"value\": 80},\n          {\"color\": \"red\", \"value\": 90}\n        ]\n      }\n    }\n  }\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | select(.type == \"gauge\") | .fieldConfig.defaults.thresholds'\n```"),
    ("grafana-stat-panel-error", "Grafana Stat Panel Error", "How to fix Grafana stat panel errors", "## Common Causes\n\n- Stat panel showing NaN\n- Color mode not matching\n- Value mappings not applied\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | select(.type == \"stat\") | .options'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | select(.type == \"stat\") | .fieldConfig'\n```"),
    ("grafana-table-error", "Grafana Table Panel Error", "How to fix Grafana table panel errors", "## Common Causes\n\n- Column types incorrectly detected\n- Table format not matching data\n- Column filtering not working\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | select(.type == \"table\") | .options'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | select(.type == \"table\") | .fieldConfig'\n```"),
    ("grafana-geomap-error", "Grafana Geomap Error", "How to fix Grafana geomap panel errors", "## Common Causes\n\n- Latitude/longitude fields not mapped\n- Map provider API key invalid\n- Data points outside visible bounds\n\n## How to Fix\n\n```json\n{\n  \"options\": {\n    \"tooltip\": {\"mode\": \"single\"}\n  }\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | select(.type == \"geomap\") | .options'\n```"),
    ("grafana-heatmap-error", "Grafana Heatmap Error", "How to fix Grafana heatmap panel errors", "## Common Causes\n\n- Data format not compatible\n- Bucket size calculation incorrect\n- Color scheme not showing gradient\n\n## How to Fix\n\n```json\n{\n  \"type\": \"heatmap\",\n  \"options\": {\n    \"calculate\": true,\n    \"yAxis\": {\"unit\": \"ms\"},\n    \"color\": {\"mode\": \"scheme\", \"scheme\": \"Oranges\"}\n  }\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | select(.type == \"heatmap\") | .options'\n```"),
    ("grafana-time-series-error", "Grafana Time Series Error", "How to fix Grafana time series panel errors", "## Common Causes\n\n- Data not in correct format\n- Legend not showing all series\n- Graph line interpolation incorrect\n\n## How to Fix\n\n```json\n{\n  \"options\": {\n    \"tooltip\": {\"mode\": \"multi\"},\n    \"legend\": {\"displayMode\": \"table\", \"placement\": \"bottom\"}\n  }\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | select(.type == \"timeseries\") | .options'\n```"),
    ("grafana-variables-error", "Grafana Template Variables Error", "How to fix Grafana variable errors", "## Common Causes\n\n- Variable query returning empty results\n- Variable values not updating\n- Cross-variable dependency not configured\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.templating.list[] | {name: .name, query: .query}'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" \"http://localhost:3000/api/datasources/proxy/ABC123/api/v1/label/__name__/values\" | jq '.data'\n```"),
    ("grafana-row-error", "Grafana Row Collapse Error", "How to fix Grafana row collapse errors", "## Common Causes\n\n- Row collapsed state not saving\n- Panels inside row not loading\n- Row height causing layout issues\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | select(.type == \"row\") | {collapsed: .collapsed}'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | select(.type == \"row\") | .title'\n```"),
    ("grafana-oncall-error", "Grafana OnCall Error", "How to fix Grafana OnCall integration errors", "## Common Causes\n\n- OnCall plugin not installed\n- API token invalid\n- Escalation chain misconfigured\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/plugins/grafana-oncall-app/settings | jq '.enabled'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/plugins/grafana-oncall-app/api/integrations | jq '.[].name'\n```"),
    ("grafana-row-repeat-error", "Grafana Row Repeat Error", "How to fix Grafana row repeat errors", "## Common Causes\n\n- Repeat variable not defined\n- Variable values empty\n- Row not configured for repeat\n\n## How to Fix\n\n```json\n{\n  \"type\": \"row\",\n  \"repeat\": \"instance\"\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | select(.repeat != null) | {title: .title, repeat: .repeat}'\n```"),
    ("grafana-organization-creation-error", "Grafana Organization Creation Error", "How to fix Grafana organization creation errors", "## Common Causes\n\n- Organization name already exists\n- Maximum org limit reached\n- Insufficient admin permissions\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer ADMIN_KEY\" http://localhost:3000/api/orgs | jq '.[].name'\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer ADMIN_KEY\" -d '{\"name\":\"NewOrg\"}' http://localhost:3000/api/orgs\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer ADMIN_KEY\" http://localhost:3000/api/orgs | jq '.[].name'\n```"),
    ("grafana-dashboard-import-error", "Grafana Dashboard Import Error", "How to fix Grafana dashboard import errors", "## Common Causes\n\n- Dashboard JSON invalid\n- Datasource references not matching\n- Plugin dependencies missing\n\n## How to Fix\n\n```bash\npython3 -m json.tool dashboard.json > /dev/null && echo \"Valid JSON\"\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d @dashboard.json http://localhost:3000/api/dashboards/db\n```\n\n## Examples\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"dashboard\":{\"id\":null},\"overwrite\":true}' http://localhost:3000/api/dashboards/import\n```"),
    ("grafana-dashboard-delete-error", "Grafana Dashboard Delete Error", "How to fix Grafana dashboard deletion errors", "## Common Causes\n\n- Dashboard is provisioned\n- Insufficient permissions\n- Dashboard referenced by alert rules\n\n## How to Fix\n\n```bash\ncurl -X DELETE -H \"Authorization: Bearer ADMIN_KEY\" http://localhost:3000/api/dashboards/db/DASHBOARD_UID\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer ADMIN_KEY\" http://localhost:3000/api/search?query=old | jq '.[].uid'\ncurl -X DELETE -H \"Authorization: Bearer ADMIN_KEY\" http://localhost:3000/api/dashboards/db/OLD_UID\n```"),
    ("grafana-dashboard-uid-error", "Grafana Dashboard UID Error", "How to fix Grafana dashboard UID errors", "## Common Causes\n\n- Duplicate dashboard UIDs\n- UID contains invalid characters\n- UID too long or too short\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/search | jq -r '.[].uid' | sort | uniq -d\n```\n\n## Examples\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"dashboard\":{\"uid\":\"my-unique-id\",\"title\":\"My Dashboard\"}}' http://localhost:3000/api/dashboards/db\n```"),
    ("grafana-dashboard-schema-version-error", "Grafana Dashboard Schema Version Error", "How to fix Grafana dashboard schema version errors", "## Common Causes\n\n- Dashboard exported from newer version\n- Schema version too old\n- Manual JSON edit broke schema\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.schemaVersion'\ngrafana-cli --version\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.schemaVersion'\n```"),
    ("grafana-dashboard-folder-permission-error", "Grafana Dashboard Folder Permission Error", "How to fix Grafana dashboard folder permission errors", "## Common Causes\n\n- User not granted access to folder\n- Team folder permissions not configured\n- Default org role too restrictive\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"items\":[{\"teamId\":1,\"permission\":2}]}' http://localhost:3000/api/folders/FOLDER_UID/permissions\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/folders/FOLDER_UID/permissions | jq '.items[]'\n```"),
    ("grafana-alert-group-error", "Grafana Alert Group Error", "How to fix Grafana alert group errors", "## Common Causes\n\n- Alert group contains no rules\n- Group interval too short\n- Rules within group conflicting\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/v1/rules | jq '.data.groups[] | {name: .name}'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/v1/rules | jq '.data.groups[] | select(.name == \"my-group\") | .rules[] | {name: .name, state: .state}'\n```"),
    ("grafana-alert-silence-error", "Grafana Alert Silence Error", "How to fix Grafana alert silence errors", "## Common Causes\n\n- Silence matcher syntax wrong\n- Start/end time in wrong format\n- Insufficient permissions\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"matchers\":[{\"name\":\"alertname\",\"value\":\"HighError\",\"isRegex\":false}],\"startsAt\":\"2024-01-01T00:00:00Z\",\"endsAt\":\"2024-01-02T00:00:00Z\",\"createdBy\":\"admin\",\"comment\":\"Maintenance\"}' http://localhost:3000/api/alertmanager/grafana/api/v2/silences\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/alertmanager/grafana/api/v2/silences | jq '.data[] | {id: .id, matchers: .matchers}'\n```"),
    ("grafana-alert-inhibition-error", "Grafana Alert Inhibition Error", "How to fix Grafana alert inhibition errors", "## Common Causes\n\n- Source matchers not matching any alerts\n- Target and source mismatch\n- Rules ordering incorrect\n\n## How to Fix\n\n```yaml\ninhibit_rules:\n  - source_match:\n      severity: 'critical'\n    target_match:\n      severity: 'warning'\n    equal: ['alertname', 'instance']\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/alertmanager/grafana/api/v2/status | jq '.config.original'\n```"),
    ("grafana-dashboard-uid-duplicate-error", "Grafana Dashboard UID Duplicate Error", "How to fix Grafana duplicate dashboard UID errors", "## Common Causes\n\n- Multiple dashboards with same UID\n- Provisioning creating duplicates\n- Import creating duplicate UIDs\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/search | jq -r '.[].uid' | sort | uniq -d\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/search | jq -r '.[].uid' | sort | uniq -c | sort -rn | head\n```"),
    ("grafana-dashboard-nested-variable-error", "Grafana Dashboard Nested Variable Error", "How to fix Grafana nested variable errors", "## Common Causes\n\n- Dependent variable referencing non-existent parent\n- Circular dependencies\n- Variable query using wrong datasource\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.templating.list[] | {name: .name, query: .query}'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.templating.list[] | {name: .name, type: .type}'\n```"),
    ("grafana-dashboard-constant-variable-error", "Grafana Dashboard Constant Variable Error", "How to fix Grafana constant variable errors", "## Common Causes\n\n- Constant variable value not set\n- Variable name conflicts with reserved names\n\n## How to Fix\n\n```json\n{\n  \"name\": \"ENVIRONMENT\",\n  \"type\": \"constant\",\n  \"query\": \"production\",\n  \"current\": {\"text\": \"production\", \"value\": \"production\"}\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.templating.list[] | select(.type == \"constant\") | {name: .name}'\n```"),
    ("grafana-dashboard-ad-hoc-variable-error", "Grafana Dashboard Ad Hoc Variable Error", "How to fix Grafana ad-hoc filter variable errors", "## Common Causes\n\n- Ad-hoc filter datasource mismatch\n- Filter keys not available\n- Too many filters slowing queries\n\n## How to Fix\n\n```json\n{\n  \"name\": \"filters\",\n  \"type\": \"adhoc\",\n  \"datasource\": {\"type\": \"prometheus\", \"uid\": \"prometheus\"}\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.templating.list[] | select(.type == \"adhoc\")'\n```"),
    ("grafana-dashboard-interval-variable-error", "Grafana Dashboard Interval Variable Error", "How to fix Grafana interval variable errors", "## Common Causes\n\n- Interval auto calculation wrong\n- Interval not matching query step\n- Selected interval not valid\n\n## How to Fix\n\n```json\n{\n  \"name\": \"interval\",\n  \"type\": \"interval\",\n  \"query\": \"1m,5m,15m,30m,1h\",\n  \"auto\": true,\n  \"auto_min\": \"1m\"\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.templating.list[] | select(.type == \"interval\") | {query: .query, auto: .auto}'\n```"),
    ("grafana-dashboard-custom-variable-error", "Grafana Dashboard Custom Variable Error", "How to fix Grafana custom variable errors", "## Common Causes\n\n- Custom values not matching format\n- Multi-value selection not working\n- All value option not configured\n\n## How to Fix\n\n```json\n{\n  \"name\": \"severity\",\n  \"type\": \"custom\",\n  \"query\": \"info,warning,error,critical\"\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.templating.list[] | select(.type == \"custom\") | {name: .name}'\n```"),
    ("grafana-dashboard-text-box-variable-error", "Grafana Dashboard TextBox Variable Error", "How to fix Grafana textbox variable errors", "## Common Causes\n\n- Textbox input not sanitizing special characters\n- Empty textbox value causing query failure\n\n## How to Fix\n\n```json\n{\n  \"name\": \"search\",\n  \"type\": \"textbox\",\n  \"query\": \"default-value\"\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.templating.list[] | select(.type == \"textbox\") | {name: .name}'\n```"),
    ("grafana-dashboard-link-error", "Grafana Dashboard Link Error", "How to fix Grafana dashboard link errors", "## Common Causes\n\n- Link pointing to wrong UID\n- Variable not interpolated in link URL\n- Link type incorrect\n\n## How to Fix\n\n```json\n{\n  \"links\": [{\n    \"title\": \"Overview\",\n    \"type\": \"dashboards\",\n    \"tags\": [\"overview\"]\n  }]\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.links[] | {title: .title, type: .type}'\n```"),
    ("grafana-dashboard-annotation-query-error", "Grafana Dashboard Annotation Query Error", "How to fix Grafana annotation query errors", "## Common Causes\n\n- Annotation datasource not configured\n- Query returning no data\n- Too many annotations cluttering graph\n\n## How to Fix\n\n```json\n{\n  \"annotations\": {\n    \"list\": [{\n      \"name\": \"Deployments\",\n      \"datasource\": {\"type\": \"grafana\", \"uid\": \"-- Grafana --\"},\n      \"enable\": true,\n      \"query\": \"deployments\"\n    }]\n  }\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.annotations.list[] | {name: .name, query: .query}'\n```"),
    ("grafana-dashboard-query-override-error", "Grafana Dashboard Query Override Error", "How to fix Grafana query override errors", "## Common Causes\n\n- Query target not referencing correct datasource\n- Override rules conflicting\n- Query refId mismatch\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[0].targets[] | {refId: .refId, expr: .expr}'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | {title: .title, datasource: .datasource}'\n```"),
    ("grafana-dashboard-field-override-error", "Grafana Dashboard Field Override Error", "How to fix Grafana field override errors", "## Common Causes\n\n- Override matcher not matching any fields\n- Override property incompatible with panel type\n- Multiple overrides conflicting\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[0].fieldConfig.overrides[]'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[0].fieldConfig.overrides | length'\n```"),
    ("grafana-dashboard-value-mapping-error", "Grafana Dashboard Value Mapping Error", "How to fix Grafana value mapping errors", "## Common Causes\n\n- Value map not matching returned values\n- Range mapping boundaries incorrect\n- Special value mapping not triggered\n\n## How to Fix\n\n```json\n{\n  \"fieldConfig\": {\n    \"defaults\": {\n      \"mappings\": [\n        {\"type\": \"value\", \"options\": {\"0\": {\"text\": \"DOWN\"}, \"1\": {\"text\": \"UP\"}}}\n      ]\n    }\n  }\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[0].fieldConfig.defaults.mappings'\n```"),
    ("grafana-dashboard-threshold-override-error", "Grafana Dashboard Threshold Override Error", "How to fix Grafana threshold override errors", "## Common Causes\n\n- Threshold steps incorrectly ordered\n- Override threshold not applying\n- Step value null position wrong\n\n## How to Fix\n\n```json\n{\n  \"fieldConfig\": {\n    \"defaults\": {\n      \"thresholds\": {\n        \"mode\": \"absolute\",\n        \"steps\": [\n          {\"color\": \"green\", \"value\": null},\n          {\"color\": \"yellow\", \"value\": 50},\n          {\"color\": \"red\", \"value\": 80}\n        ]\n      }\n    }\n  }\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[0].fieldConfig.defaults.thresholds'\n```"),
    ("grafana-dashboard-unit-error", "Grafana Dashboard Unit Error", "How to fix Grafana panel unit errors", "## Common Causes\n\n- Unit not matching data type\n- Custom unit not displaying correctly\n\n## How to Fix\n\n```json\n{\n  \"fieldConfig\": {\n    \"defaults\": {\"unit\": \"bytes\"}\n  }\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[].fieldConfig.defaults.unit'\n```"),
    ("grafana-dashboard-color-scheme-error", "Grafana Dashboard Color Scheme Error", "How to fix Grafana color scheme errors", "## Common Causes\n\n- Color scheme not matching data\n- Custom color palette not applied\n\n## How to Fix\n\n```json\n{\n  \"fieldConfig\": {\n    \"defaults\": {\n      \"color\": {\"mode\": \"palette-classic\"}\n    }\n  }\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[0].fieldConfig.defaults.color'\n```"),
    ("grafana-dashboard-tooltip-error", "Grafana Dashboard Tooltip Error", "How to fix Grafana tooltip errors", "## Common Causes\n\n- Tooltip mode not showing all series\n- Tooltip content missing fields\n\n## How to Fix\n\n```json\n{\n  \"options\": {\n    \"tooltip\": {\"mode\": \"multi\", \"sort\": \"desc\"}\n  }\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[0].options.tooltip'\n```"),
    ("grafana-dashboard-legend-error", "Grafana Dashboard Legend Error", "How to fix Grafana legend errors", "## Common Causes\n\n- Legend showing raw label values\n- Legend table not displaying columns\n- Legend position overlapping panel\n\n## How to Fix\n\n```json\n{\n  \"options\": {\n    \"legend\": {\n      \"displayMode\": \"table\",\n      \"placement\": \"right\",\n      \"calcs\": [\"mean\", \"max\"]\n    }\n  }\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[0].options.legend'\n```"),
    ("grafana-dashboard-data-link-error", "Grafana Dashboard Data Link Error", "How to fix Grafana data link errors", "## Common Causes\n\n- Data link URL not interpolating variables\n- Data link title empty\n- Target blank not opening new tab\n\n## How to Fix\n\n```json\n{\n  \"links\": [{\n    \"title\": \"Drilldown\",\n    \"url\": \"/d/other?var-instance=${__value.raw}\",\n    \"targetBlank\": true\n  }]\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[0].links[]'\n```"),
    ("grafana-dashboard-transformation-filter-error", "Grafana Dashboard Transform Filter Error", "How to fix Grafana transformation filter errors", "## Common Causes\n\n- Filter condition returning no rows\n- Rename mapping not matching fields\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[0].transformations[]'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | {title: .title, transformations: (.transformations | length)}'\n```"),
    ("grafana-dashboard-reduce-transformation-error", "Grafana Dashboard Reduce Transform Error", "How to fix Grafana reduce transformation errors", "## Common Causes\n\n- Reduce operation on non-numeric data\n- Empty input producing NaN\n\n## How to Fix\n\n```json\n{\n  \"id\": \"reduce\",\n  \"options\": {\n    \"mode\": \"reduceFields\",\n    \"reducers\": [\"lastNotNull\", \"mean\", \"max\"]\n  }\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | .transformations[] | select(.id == \"reduce\")'\n```"),
    ("grafana-dashboard-join-transformation-error", "Grafana Dashboard Join Transform Error", "How to fix Grafana join transformation errors", "## Common Causes\n\n- Join field names not matching\n- Outer join producing too many rows\n\n## How to Fix\n\n```json\n{\n  \"id\": \"joinByField\",\n  \"options\": {\"byField\": \"Time\", \"mode\": \"outer\"}\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | .transformations[] | select(.id == \"joinByField\")'\n```"),
    ("grafana-dashboard-organize-transformation-error", "Grafana Dashboard Organize Transform Error", "How to fix Grafana organize transformation errors", "## Common Causes\n\n- Hide operation not removing field\n- Rename not applying to correct field\n\n## How to Fix\n\n```json\n{\n  \"id\": \"organize\",\n  \"options\": {\n    \"excludeByName\": {\"Time\": true},\n    \"renameByName\": {\"Value\": \"Response Time\"}\n  }\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | .transformations[] | select(.id == \"organize\")'\n```"),
    ("grafana-dashboard-group-by-transformation-error", "Grafana Dashboard Group By Transform Error", "How to fix Grafana group by transformation errors", "## Common Causes\n\n- Group by field not found\n- Aggregation function incompatible\n\n## How to Fix\n\n```json\n{\n  \"id\": \"groupBy\",\n  \"options\": {\n    \"fields\": {\n      \"instance\": {\"aggregations\": [], \"operation\": \"groupById\"},\n      \"Value\": {\"aggregations\": [\"mean\"], \"operation\": \"aggregate\"}\n    }\n  }\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | .transformations[] | select(.id == \"groupBy\")'\n```"),
    ("grafana-dashboard-calculate-field-error", "Grafana Dashboard Calculate Field Error", "How to fix Grafana calculate field transformation errors", "## Common Causes\n\n- Field names in formula not found\n- Divide by zero error\n- Numeric conversion failing\n\n## How to Fix\n\n```json\n{\n  \"id\": \"calculateField\",\n  \"options\": {\n    \"mode\": \"binaryOperation\",\n    \"binaryOperation\": {\n      \"leftField\": \"requests\",\n      \"operator\": \"/\",\n      \"rightField\": \"errors\"\n    }\n  }\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | .transformations[] | select(.id == \"calculateField\")'\n```"),
    ("grafana-dashboard-sort-by-error", "Grafana Dashboard Sort By Transform Error", "How to fix Grafana sort by transformation errors", "## Common Causes\n\n- Sort field not found\n- Sort direction not applied\n\n## How to Fix\n\n```json\n{\n  \"id\": \"sortBy\",\n  \"options\": {\n    \"sort\": [{\"field\": \"Value\", \"desc\": true}]\n  }\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | .transformations[] | select(.id == \"sortBy\")'\n```"),
    ("grafana-dashboard-configuration-export-error", "Grafana Dashboard Export Error", "How to fix Grafana dashboard export errors", "## Common Causes\n\n- Export format not compatible\n- Datasource UIDs not exported\n- Variables not included\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard' > exported.json\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard' > dashboard-export.json\n```"),
    ("grafana-dashboard-public-error", "Grafana Dashboard Public Access Error", "How to fix Grafana public dashboard errors", "## Common Causes\n\n- Anonymous access not enabled\n- Public dashboard not configured\n- Sensitive data exposed\n\n## How to Fix\n\n```ini\n[auth.anonymous]\nenabled = true\norg_name = Main Org.\norg_role = Viewer\n```\n\n## Examples\n\n```bash\ncurl -s http://localhost:3000/api/org | jq '.name'\n```"),
    ("grafana-dashboard-json-model-error", "Grafana Dashboard JSON Model Error", "How to fix Grafana dashboard JSON model errors", "## Common Causes\n- JSON syntax error\n- Missing required fields (title, panels)\n- Panel gridPos invalid\n\n## How to Fix\n\n```bash\npython3 -m json.tool dashboard.json\npython3 -c \"import json; d=json.load(open('dashboard.json')); print('title' in d, 'panels' in d)\"\n```\n\n## Examples\n\n```bash\npython3 -c \"import json; d=json.load(open('dashboard.json')); print(f'Panels: {len(d.get(\\\"panels\\\", []))}')\"\n```"),
    ("grafana-dashboard-gridpos-error", "Grafana Dashboard GridPos Error", "How to fix Grafana grid position errors", "## Common Causes\n- Panel gridPos values overlap\n- Panel position outside bounds\n- Panel height or width zero\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | {title: .title, gridPos: .gridPos}'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[] | .gridPos | \"\\\\(.x)x\\\\(.y) \\\\(.w)x\\\\(.h)\"'\n```"),
    ("grafana-dashboard-time-range-error", "Grafana Dashboard Time Range Error", "How to fix Grafana time range errors", "## Common Causes\n- Time range not matching data retention\n- Relative time range showing no data\n- Time zone conversion wrong\n\n## How to Fix\n\n```json\n{\n  \"time\": {\n    \"from\": \"now-6h\",\n    \"to\": \"now\",\n    \"refresh_intervals\": [\"5s\", \"10s\", \"30s\", \"1m\"]\n  },\n  \"timezone\": \"browser\"\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.time'\n```"),
    ("grafana-dashboard-refresh-error", "Grafana Dashboard Auto Refresh Error", "How to fix Grafana auto refresh errors", "## Common Causes\n- Auto refresh interval not configured\n- Refresh causing excessive queries\n\n## How to Fix\n\n```json\n{\n  \"time\": {\n    \"refresh_intervals\": [\"5s\", \"10s\", \"30s\", \"1m\", \"5m\"]\n  }\n}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.time.refresh_intervals'\n```"),
    ("grafana-dashboard-render-error", "Grafana Dashboard Render Error", "How to fix Grafana dashboard render errors", "## Common Causes\n- Image renderer plugin missing\n- Dashboard too complex for timeout\n- Font rendering issues\n\n## How to Fix\n\n```bash\ngrafana-cli plugins install grafana-image-renderer\nsudo systemctl restart grafana-server\n```\n\n## Examples\n\n```bash\ncurl -H \"Authorization: Bearer API_KEY\" \"http://localhost:3000/render/d/UID?orgId=1&width=1200&height=600\" -o dashboard.png\n```"),
    ("grafana-dashboard-cors-error", "Grafana Dashboard CORS Error", "How to fix Grafana CORS errors", "## Common Causes\n- CORS not configured\n- Dashboard embed blocked by browser\n- Iframe src not whitelisted\n\n## How to Fix\n\n```ini\n[security]\nallow_embedding = true\n```\n\n## Examples\n\n```bash\ncurl -I -H \"Origin: http://other.com\" http://localhost:3000/api/health | grep -i access-control\n```"),
    ("grafana-dashboard-proxy-error", "Grafana Dashboard Proxy Error", "How to fix Grafana datasource proxy errors", "## Common Causes\n- Datasource proxy URL incorrect\n- Authentication failing through proxy\n- Proxy timeout too short\n\n## How to Fix\n\n```bash\ncurl -H \"Authorization: Bearer API_KEY\" \"http://localhost:3000/api/datasources/proxy/DS_UID/api/v1/query?query=up\"\n```\n\n## Examples\n\n```bash\ncurl -H \"Authorization: Bearer API_KEY\" \"http://localhost:3000/api/datasources/proxy/DS_UID/api/v1/status/config\"\n```"),
    ("grafana-dashboard-csp-error", "Grafana Dashboard CSP Error", "How to fix Grafana CSP errors", "## Common Causes\n- CSP blocking inline scripts\n- External resource loading blocked\n\n## How to Fix\n\n```ini\n[security]\ncontent_security_policy = true\ncontent_security_policy_template = \"script-src 'self' 'unsafe-inline' 'unsafe-eval'; style-src 'self' 'unsafe-inline';\"\n```\n\n## Examples\n\n```bash\ncurl -I http://localhost:3000/api/health | grep -i content-security-policy\n```"),
    ("grafana-dashboard-ldap-error", "Grafana Dashboard LDAP Error", "How to fix Grafana LDAP authentication errors", "## Common Causes\n- LDAP server unreachable\n- Bind DN or password wrong\n- User search base incorrect\n\n## How to Fix\n\n```toml\n[[servers]]\nhost = \"ldap.example.com\"\nbind_dn = \"cn=admin,dc=example,dc=com\"\nsearch_filter = \"(cn=%s)\"\nsearch_base_dns = [\"ou=users,dc=example,dc=com\"]\n```\n\n## Examples\n\n```bash\nldapsearch -x -H ldap://ldap.example.com -b \"ou=users,dc=example,dc=com\" \"(cn=testuser)\"\n```"),
    ("grafana-dashboard-oauth-error", "Grafana Dashboard OAuth Error", "How to fix Grafana OAuth errors", "## Common Causes\n- OAuth provider misconfigured\n- Client ID or secret wrong\n- Callback URL mismatch\n\n## How to Fix\n\n```ini\n[auth.generic_oauth]\nenabled = true\nclient_id = YOUR_ID\nclient_secret = YOUR_SECRET\nauth_url = https://provider.com/authorize\ntoken_url = https://provider.com/token\n```\n\n## Examples\n\n```bash\ncurl -s http://localhost:3000/api/login/generic_oauth -v 2>&1 | grep -i location\n```"),
    ("grafana-dashboard-saml-error", "Grafana Dashboard SAML Error", "How to fix Grafana SAML errors", "## Common Causes\n- SAML metadata XML invalid\n- Certificate not matching IdP\n- ACS URL incorrect\n\n## How to Fix\n\n```ini\n[auth.saml]\nenabled = true\ncertificate_path = /etc/grafana/saml/cert.pem\nprivate_key_path = /etc/grafana/saml/key.pem\nmetadata_path = /etc/grafana/saml/metadata.xml\n```\n\n## Examples\n\n```bash\nxmllint --noout /etc/grafana/saml/metadata.xml\n```"),
    ("grafana-dashboard-jwt-error", "Grafana Dashboard JWT Auth Error", "How to fix Grafana JWT auth errors", "## Common Causes\n- JWT token expired\n- JWT secret not matching\n- Claims not mapping to Grafana user\n\n## How to Fix\n\n```ini\n[auth.jwt]\nenabled = true\nheader_name = X-JWT-Assertion\nemail_claim = email\nusername_claim = sub\n```\n\n## Examples\n\n```bash\necho \"TOKEN\" | cut -d'.' -f2 | base64 -d 2>/dev/null | jq .\n```"),
    ("grafana-dashboard-api-error", "Grafana Dashboard API Error", "How to fix Grafana API errors", "## Common Causes\n- API endpoint incorrect\n- Rate limiting too aggressive\n- API key missing or invalid\n\n## How to Fix\n\n```bash\ncurl -s http://localhost:3000/api/health | jq '.'\n```\n\n## Examples\n\n```bash\ncurl -s http://localhost:3000/api/frontend/settings | jq '.buildInfo.version'\n```"),
    ("grafana-dashboard-datasource-migration-error", "Grafana Dashboard Datasource Migration Error", "How to fix Grafana datasource migration errors", "## Common Causes\n- Datasource UIDs changed after migration\n- Old datasource references in panels\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/dashboards/uid/UID | jq '.dashboard.panels[].datasource | select(.uid == null)'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/datasources | jq '.[] | {name: .name, uid: .uid}'\n```"),
    ("grafana-dashboard-provisioning-sync-error", "Grafana Dashboard Provisioning Sync Error", "How to fix Grafana provisioning sync errors", "## Common Causes\n- Provisioned dashboard modified in UI not syncing\n- File changes not picked up\n\n## How to Fix\n\n```bash\nsudo systemctl restart grafana-server\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/search | jq '.[] | select(.provisioned == true) | .title'\n```"),
    ("grafana-dashboard-provisioning-folder-error", "Grafana Dashboard Provisioning Folder Error", "How to fix Grafana provisioning folder errors", "## Common Causes\n- Folder not created before dashboard provisioning\n- Folder UID mismatch\n\n## How to Fix\n\n```yaml\napiVersion: 1\nproviders:\n  - name: 'default'\n    folder: 'Production'\n    type: file\n    options:\n      path: /var/lib/grafana/dashboards\n```\n\n## Examples\n\n```bash\njournalctl -u grafana-server | grep -i folder\n```"),
    ("grafana-dashboard-provisioning-datasource-error", "Grafana Dashboard Provisioning Datasource Error", "How to fix Grafana provisioning datasource errors", "## Common Causes\n- Datasource not provisioned before dashboard\n- Datasource URL unreachable at provision time\n\n## How to Fix\n\n```yaml\napiVersion: 1\ndatasources:\n  - name: Prometheus\n    type: prometheus\n    access: proxy\n    url: http://prometheus:9090\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/datasources | jq '.[].name'\n```"),
    ("grafana-dashboard-provisioning-contact-point-error", "Grafana Dashboard Provisioning Contact Point Error", "How to fix Grafana provisioning contact point errors", "## Common Causes\n- Contact point referenced by alert not provisioned\n- Settings incomplete\n\n## How to Fix\n\n```yaml\napiVersion: 1\ncontactPoints:\n  - orgId: 1\n    name: ops-team\n    receivers:\n      - uid: slack-1\n        type: slack\n        settings:\n          url: https://hooks.slack.com/services/T00/B00/xxx\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/v1/provisioning/contact-points | jq '.[].name'\n```"),
    ("grafana-dashboard-provisioning-notification-policy-error", "Grafana Dashboard Provisioning Notification Policy Error", "How to fix Grafana provisioning notification policy errors", "## Common Causes\n- Notification policy tree malformed\n- Route not matching alert labels\n\n## How to Fix\n\n```yaml\napiVersion: 1\npolicies:\n  - orgId: 1\n    receiver: default\n    group_by: ['alertname', 'severity']\n    group_wait: 30s\n    group_interval: 5m\n    repeat_interval: 4h\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/v1/provisioning/policies | jq '.'\n```"),
    ("grafana-dashboard-provisioning-template-error", "Grafana Dashboard Provisioning Template Error", "How to fix Grafana provisioning template errors", "## Common Causes\n- Template syntax invalid\n- Template variables not defined\n\n## How to Fix\n\n```yaml\napiVersion: 1\ntemplates:\n  - orgId: 1\n    name: default\n    template: |\n      {{ define \"slack.title\" }}[{{ .Status | toUpper }}] {{ .Labels.alertname }}{{ end }}\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/v1/provisioning/templates | jq '.[].name'\n```"),
    ("grafana-dashboard-provisioning-mute-time-error", "Grafana Dashboard Provisioning Mute Time Error", "How to fix Grafana provisioning mute time errors", "## Common Causes\n- Mute time interval syntax wrong\n- Time range not valid\n\n## How to Fix\n\n```yaml\napiVersion: 1\nmuteTimeIntervals:\n  - orgId: 1\n    name: weekends\n    timeIntervals:\n      - weekdays: ['saturday', 'sunday']\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/v1/provisioning/mute-timings | jq '.[].name'\n```"),
    ("grafana-dashboard-screenshot-error", "Grafana Dashboard Screenshot Error", "How to fix Grafana dashboard screenshot errors", "## Common Causes\n- Screenshot service not configured\n- Dashboard too large for screenshot\n- Authentication failing for render endpoint\n\n## How to Fix\n\n```ini\n[rendering]\nrenderer = plugin\nconcurrent_render_request_limit = 4\n```\n\n## Examples\n\n```bash\ncurl -H \"Authorization: Bearer API_KEY\" \"http://localhost:3000/render/d/UID?orgId=1&width=1920&height=1080&scale=2\" -o screenshot.png\n```"),
    ("grafana-dashboard-embed-error", "Grafana Dashboard Embed Error", "How to fix Grafana dashboard embed errors", "## Common Causes\n- Embedding disabled in configuration\n- CSP blocking iframe\n- Cookie SameSite blocking session\n\n## How to Fix\n\n```ini\n[security]\nallow_embedding = true\ncookie_samesite = none\ncookie_secure = true\n```\n\n## Examples\n\n```bash\ncurl -s http://localhost:3000/api/frontend/settings | jq '.allowEmbedding'\n```"),
    ("grafana-dashboard-share-error", "Grafana Dashboard Share Error", "How to fix Grafana dashboard share errors", "## Common Causes\n- Share link not public\n- Snapshot storage not configured\n- Share link expired\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"dashboard\":{},\"expires\":86400}' http://localhost:3000/api/snapshots\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/snapshots | jq '.url'\n```"),
    ("grafana-dashboard-api-key-scopes-error", "Grafana Dashboard API Key Scopes Error", "How to fix Grafana API key scope errors", "## Common Causes\n- API key scope too restricted\n- Service account token missing required role\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer ADMIN_KEY\" -d '{\"name\":\"read-only\",\"role\":\"Viewer\"}' http://localhost:3000/api/auth/keys\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer ADMIN_KEY\" http://localhost:3000/api/auth/keys | jq '.[] | {name: .name, role: .role}'\n```"),
    ("grafana-dashboard-service-account-token-error", "Grafana Dashboard Service Account Token Error", "How to fix Grafana service account token errors", "## Common Causes\n- Service account does not exist\n- Token rotation not configured\n- Token expired\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer ADMIN_KEY\" -d '{\"name\":\"dashboard-automation\",\"role\":\"Editor\"}' http://localhost:3000/api/serviceaccounts\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer ADMIN_KEY\" http://localhost:3000/api/serviceaccounts | jq '.items[].name'\n```"),
    ("grafana-dashboard-provisioning-github-error", "Grafana Dashboard Provisioning GitHub Error", "How to fix Grafana provisioning from GitHub errors", "## Common Causes\n- GitHub token expired\n- Repository path incorrect\n- Branch not found\n\n## How to Fix\n\n```yaml\napiVersion: 1\nproviders:\n  - name: 'github'\n    type: github\n    options:\n      owner: myorg\n      repository: grafana-dashboards\n      token: ghp_xxx\n      branch: main\n      path: dashboards\n```\n\n## Examples\n\n```bash\ncurl -H \"Authorization: token ghp_xxx\" \"https://api.github.com/repos/myorg/grafana-dashboards/contents/dashboards\" | jq '.[].name'\n```"),
    ("grafana-dashboard-provisioning-gitlab-error", "Grafana Dashboard Provisioning GitLab Error", "How to fix Grafana provisioning from GitLab errors", "## Common Causes\n- GitLab token invalid\n- Project ID wrong\n\n## How to Fix\n\n```yaml\napiVersion: 1\nproviders:\n  - name: 'gitlab'\n    type: gitlab\n    options:\n      project: mygroup/myproject\n      token: glpat-xxx\n      branch: main\n      path: dashboards\n```\n\n## Examples\n\n```bash\ncurl -H \"PRIVATE-TOKEN: glpat-xxx\" \"https://gitlab.com/api/v4/projects/mygroup%2Fmyproject/repository/tree?path=dashboards\" | jq '.[].name'\n```"),
    ("grafana-dashboard-provisioning-bitbucket-error", "Grafana Dashboard Provisioning Bitbucket Error", "How to fix Grafana provisioning from Bitbucket errors", "## Common Causes\n- Bitbucket credentials invalid\n- Workspace or repository wrong\n\n## How to Fix\n\n```yaml\napiVersion: 1\nproviders:\n  - name: 'bitbucket'\n    type: bitbucket\n    options:\n      owner: myworkspace\n      repository: myrepo\n      branch: main\n      path: dashboards\n```\n\n## Examples\n\n```bash\ncurl -u \"user:app-password\" \"https://api.bitbucket.org/2.0/repositories/myworkspace/myrepo/src/main/dashboards/\" | jq '.values[].name'\n```"),
    ("grafana-dashboard-provisioning-azure-error", "Grafana Dashboard Provisioning Azure DevOps Error", "How to fix Grafana provisioning from Azure DevOps errors", "## Common Causes\n- Azure DevOps PAT invalid\n- Project or repository wrong\n\n## How to Fix\n\n```yaml\napiVersion: 1\nproviders:\n  - name: 'azure'\n    type: azuredevops\n    options:\n      repo: myorg/myproject/myrepo\n      branch: main\n      path: dashboards\n```\n\n## Examples\n\n```bash\ncurl -u \":PAT\" \"https://dev.azure.com/myorg/myproject/_apis/git/repositories/myrepo/items?path=dashboards\" | jq '.value[].path'\n```"),
    ("grafana-dashboard-api-query-error", "Grafana Dashboard API Query Error", "How to fix Grafana API query errors", "## Common Causes\n- Query endpoint incorrect\n- Query body malformed\n- Datasource UID wrong\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"queries\":[{\"refId\":\"A\",\"datasource\":{\"type\":\"prometheus\",\"uid\":\"prometheus\"},\"expr\":\"up\"}],\"from\":\"now-1h\",\"to\":\"now\"}' http://localhost:3000/api/ds/query\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" \"http://localhost:3000/api/datasources/uid/prometheus/health\" | jq '.status'\n```"),
    ("grafana-dashboard-api-search-error", "Grafana Dashboard API Search Error", "How to fix Grafana API search errors", "## Common Causes\n- Search query syntax wrong\n- Type filter not matching\n\n## How to Fix\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" \"http://localhost:3000/api/search?query=production&type=dash-db\" | jq '.[].title'\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" \"http://localhost:3000/api/search?tag=team-ops\" | jq '.[].title'\n```"),
    ("grafana-dashboard-api-folder-error", "Grafana Dashboard API Folder Error", "How to fix Grafana API folder errors", "## Common Causes\n- Folder already exists with same name\n- UID collision\n- Insufficient permissions\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer ADMIN_KEY\" -d '{\"title\":\"Engineering\",\"uid\":\"eng-folder\"}' http://localhost:3000/api/folders\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer ADMIN_KEY\" http://localhost:3000/api/folders | jq '.[] | {uid: .uid, title: .title}'\n```"),
    ("grafana-dashboard-api-annotation-error", "Grafana Dashboard API Annotation Error", "How to fix Grafana API annotation errors", "## Common Causes\n- Annotation data too large\n- Time range invalid\n\n## How to Fix\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"time\":1609459200000,\"text\":\"Deployment\",\"tags\":[\"deploy\"]}' http://localhost:3000/api/annotations\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" \"http://localhost:3000/api/annotations?from=1609459200000&to=1609462800000\" | jq '.[].text'\n```"),
    ("grafana-dashboard-frontend-error", "Grafana Dashboard Frontend Error", "How to fix Grafana frontend rendering errors", "## Common Causes\n- Browser cache corrupted\n- JavaScript disabled\n- Frontend build corrupted\n\n## How to Fix\n\n```bash\nsudo systemctl restart grafana-server\n```\n\n## Examples\n\n```bash\ncurl -s http://localhost:3000/api/frontend/settings | jq '.buildInfo.version'\n```"),
    ("grafana-dashboard-backend-error", "Grafana Dashboard Backend Error", "How to fix Grafana backend server errors", "## Common Causes\n- Database connection lost\n- Backend process crashed\n- Memory exhaustion\n\n## How to Fix\n\n```bash\njournalctl -u grafana-server --since \"10 minutes ago\" | grep -i error\nsudo systemctl restart grafana-server\n```\n\n## Examples\n\n```bash\ncurl -s http://localhost:3000/api/health | jq '.database'\n```"),
    ("grafana-dashboard-database-error", "Grafana Dashboard Database Error", "How to fix Grafana database errors", "## Common Causes\n- Database connection pool exhausted\n- Migration failed during upgrade\n- SQLite file permissions wrong\n\n## How to Fix\n\n```ini\n[database]\ntype = sqlite3\npath = /var/lib/grafana/grafana.db\n```\n\n## Examples\n\n```bash\nls -la /var/lib/grafana/grafana.db\n```"),
    ("grafana-dashboard-cache-error", "Grafana Dashboard Cache Error", "How to fix Grafana cache errors", "## Common Causes\n- Cache backend unreachable\n- Cache invalidation not working\n\n## How to Fix\n\n```ini\n[caching]\nenabled = true\nbackend = memory\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/frontend/settings | jq '.caching'\n```"),
    ("grafana-dashboard-alerting-migration-error", "Grafana Dashboard Alerting Migration Error", "How to fix Grafana alerting migration errors", "## Common Causes\n- Legacy alerts not converted\n- Notification channels lost\n\n## How to Fix\n\n```bash\njournalctl -u grafana-server | grep -i \"alert migration\"\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" http://localhost:3000/api/v1/rules | jq '.data.groups[].rules[] | .title'\n```"),
    ("grafana-dashboard-auth-proxy-error", "Grafana Dashboard Auth Proxy Error", "How to fix Grafana auth proxy errors", "## Common Causes\n- Auth proxy headers not configured\n- Username header mismatch\n\n## How to Fix\n\n```ini\n[auth.proxy]\nenabled = true\nheader_name = X-WEBAUTH-USER\nheader_property = username\nauto_sign_up = true\n```\n\n## Examples\n\n```bash\ncurl -H \"X-WEBAUTH-USER: admin\" http://localhost:3000/api/org\n```"),
    ("grafana-dashboard-basic-auth-error", "Grafana Dashboard Basic Auth Error", "How to fix Grafana basic auth errors", "## Common Causes\n- Basic auth disabled\n- Credentials wrong\n\n## How to Fix\n\n```ini\n[auth.basic]\nenabled = true\n```\n\n## Examples\n\n```bash\ncurl -u admin:admin http://localhost:3000/api/org | jq '.name'\n```"),
    ("grafana-dashboard-grafana-com-error", "Grafana Dashboard Grafana.com Error", "How to fix Grafana grafana.com integration errors", "## Common Causes\n- Grafana.com account not linked\n- Plugin marketplace unreachable\n\n## How to Fix\n\n```bash\ncurl -s https://grafana.com/api/health | jq .\n```\n\n## Examples\n\n```bash\ncurl -X POST -H \"Content-Type: application/json\" -H \"Authorization: Bearer API_KEY\" -d '{\"dashboard\":null,\"overwrite\":false}' http://localhost:3000/api/dashboards/import/1\n```"),
    ("grafana-dashboard-profiling-error", "Grafana Dashboard Profiling Error", "How to fix Grafana profiling errors", "## Common Causes\n- Profiling endpoint disabled\n- Dashboard load time exceeding threshold\n\n## How to Fix\n\n```ini\n[profiling]\nenabled = true\n```\n\n## Examples\n\n```bash\ncurl -s -H \"Authorization: Bearer API_KEY\" \"http://localhost:3000/api/dashboards/uid/UID\" -w \"Total time: %{time_total}s\\n\" -o /dev/null\n```"),
    ("grafana-dashboard-certificate-error", "Grafana Dashboard Certificate Error", "How to fix Grafana TLS certificate errors", "## Common Causes\n- Self-signed certificate not trusted\n- Certificate expired\n- Certificate chain incomplete\n\n## How to Fix\n\n```ini\n[server]\nprotocol = https\ncert_file = /etc/grafana/certs/grafana.crt\ncert_key = /etc/grafana/certs/grafana.key\n```\n\n## Examples\n\n```bash\nopenssl x509 -in /etc/grafana/certs/grafana.crt -noout -dates\n```"),
]

count = 0
for slug, title, desc, body in PAGES:
    if slug in EXISTING:
        continue
    path = os.path.join(BASE, f'{slug}.md')
    with open(path, 'w') as f:
        f.write(make_page(slug, title, desc, body))
    count += 1

print(f'Generated {count} new Grafana pages (total: {len(EXISTING) + count})')
